SPIKE=/tmp/mfe-portless-spike-4

# Spin up a fake "lightfast-www" from each worktree
cat > "$SPIKE/echo.cjs" <<'EOF'
const http=require('http');
const port=Number(process.env.PORT||process.argv[2]);
const label=process.argv[3]||process.env.LABEL||'?';
http.createServer((req,res)=>{
  res.writeHead(200,{'Content-Type':'text/plain'});
  res.end(`label=${label} port=${port} path=${req.url}\n`);
}).listen(port,'127.0.0.1',()=>console.error(`listening ${label}:${port}`));
EOF

cd "$SPIKE/primary"
LABEL=primary-www portless run --name lightfast-www node "$SPIKE/echo.cjs" > /tmp/primary-www.log 2>&1 &
sleep 2
cd "$SPIKE/sibling"
LABEL=sibling-www portless run --name lightfast-www node "$SPIKE/echo.cjs" > /tmp/sibling-www.log 2>&1 &
sleep 2

echo "=== portless list ==="
portless list 2>&1

echo
echo "=== Build canonical microfrontends.json (committed shape) ==="
mkdir -p "$SPIKE/primary/apps/app" "$SPIKE/sibling/apps/app"
# Note: primary and sibling share same microfrontends.json shape (committed code)
# We write the SAME file to both — what differs is the runtime resolution
cat > "$SPIKE/canonical-mfe.json" <<'EOF'
{
  "$schema": "https://openapi.vercel.sh/microfrontends.json",
  "applications": {
    "lightfast-app": {
      "development": { "local": 4107, "fallback": "vercel.com" }
    },
    "lightfast-www": {
      "development": { "local": 4101 },
      "routing": [{ "paths": ["/docs/:path*"] }]
    }
  }
}
EOF
cp "$SPIKE/canonical-mfe.json" "$SPIKE/primary/apps/app/microfrontends.json"
cp "$SPIKE/canonical-mfe.json" "$SPIKE/sibling/apps/app/microfrontends.json"
cat "$SPIKE/canonical-mfe.json"

